"""Unit tests for MemberCollection ADT."""import pytestfrom src.models.member import Memberfrom src.collections.member_collection import MemberCollectionclass TestMemberCollection:    """Test suite for MemberCollection."""    @pytest.fixture    def empty_collection(self):        return MemberCollection()    @pytest.fixture    def sample_member(self):        return Member(            name="Jane Smith",            member_id="M001",            email="jane@example.com"        )    def test_add_member_success(self, empty_collection, sample_member):        empty_collection.add_member(sample_member)        assert empty_collection.count() == 1        assert empty_collection.find_by_id("M001") == sample_member    def test_add_duplicate_raises_error(self, empty_collection, sample_member):        empty_collection.add_member(sample_member)        with pytest.raises(ValueError, match="already exists"):            empty_collection.add_member(sample_member)    def test_remove_member_success(self, empty_collection, sample_member):        empty_collection.add_member(sample_member)        removed = empty_collection.remove_member("M001")        assert removed == sample_member        assert empty_collection.count() == 0    def test_remove_member_with_borrowed_books_fails(self, empty_collection, sample_member):        sample_member.borrow_book("ISBN-123")        empty_collection.add_member(sample_member)        with pytest.raises(ValueError, match="borrowed books"):            empty_collection.remove_member("M001")    def test_remove_member_with_fines_fails(self, empty_collection, sample_member):        sample_member.add_fine(5.00)        empty_collection.add_member(sample_member)        with pytest.raises(ValueError, match="outstanding fines"):            empty_collection.remove_member("M001")    def test_find_by_name_partial_match(self, empty_collection):        m1 = Member("Alice Johnson", "M001", "alice@test.com")        m2 = Member("Bob Williams", "M002", "bob@test.com")        m3 = Member("Charlie Johnson", "M003", "charlie@test.com")        empty_collection.add_member(m1)        empty_collection.add_member(m2)        empty_collection.add_member(m3)        results = empty_collection.find_by_name("johnson")        assert len(results) == 2        assert m1 in results        assert m3 in results        results = empty_collection.find_by_name("bob")        assert len(results) == 1        assert m2 in results    def test_get_active_members(self, empty_collection, sample_member):        m2 = Member("Inactive User", "M002", "inactive@test.com")        m2.deactivate()        empty_collection.add_member(sample_member)        empty_collection.add_member(m2)        active = empty_collection.get_active_members()        assert len(active) == 1        assert sample_member in active        assert m2 not in active    def test_get_members_with_fines(self, empty_collection, sample_member):        m2 = Member("Fined User", "M002", "fined@test.com")        m2.add_fine(10.00)        empty_collection.add_member(sample_member)        empty_collection.add_member(m2)        with_fines = empty_collection.get_members_with_fines()        assert len(with_fines) == 1        assert m2 in with_fines        assert sample_member not in with_fines